//! High-performance design matrix construction for statistical models
//!
//! This crate provides column-oriented design matrix builders that fuse
//! transformations to eliminate intermediate allocations and leverage
//! parallel computation for construction.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use formula::ModelSpec;
use ndarray::Array2;

/// Design matrix construction errors
#[derive(thiserror::Error, Debug)]
pub enum MatrixError {
    /// Data dimension mismatch
    #[error("Data dimension error: {0}")]
    Dimension(String),
    /// Variable not found in data
    #[error("Variable not found: {0}")]
    VariableNotFound(String),
}

/// Column-major design matrix builder
pub struct Builder {
    n_rows: usize,
    columns: Vec<Vec<f64>>,
}

impl Builder {
    /// Create a new builder for the given number of observations
    pub fn new(n_rows: usize) -> Self {
        Self {
            n_rows,
            columns: Vec::new(),
        }
    }

    /// Add an intercept column (all ones)
    pub fn add_intercept(&mut self) {
        self.columns.push(vec![1.0; self.n_rows]);
    }

    /// Add a continuous variable column
    pub fn add_continuous(&mut self, values: Vec<f64>) -> Result<(), MatrixError> {
        if values.len() != self.n_rows {
            return Err(MatrixError::Dimension(format!(
                "Expected {} rows, got {}",
                self.n_rows,
                values.len()
            )));
        }
        self.columns.push(values);
        Ok(())
    }

    /// Build the final design matrix
    pub fn build(self) -> Array2<f64> {
        if self.columns.is_empty() {
            return Array2::zeros((self.n_rows, 0));
        }

        let n_cols = self.columns.len();
        let mut matrix = Array2::zeros((self.n_rows, n_cols));

        for (col_idx, column) in self.columns.into_iter().enumerate() {
            for (row_idx, value) in column.into_iter().enumerate() {
                matrix[[row_idx, col_idx]] = value;
            }
        }

        matrix
    }
}

/// Build design matrix from model specification and data
pub fn build_design_matrix(_spec: &ModelSpec) -> Result<Array2<f64>, MatrixError> {
    // TODO: Implement full design matrix construction in Sprint 2
    // For now, return a simple 2x1 intercept matrix for testing
    let mut builder = Builder::new(2);
    builder.add_intercept();
    Ok(builder.build())
}

//! R-style formula parsing and design matrix specification
//!
//! This crate provides compile-time and run-time parsing of statistical formulas
//! in the R format (e.g., `y ~ x1 + x2*x3`), compiling them into optimized
//! design matrix generators.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

/// Formula parsing errors
#[derive(thiserror::Error, Debug)]
pub enum FormulaError {
    /// Parse error from pest
    #[error("Formula parse error: {0}")]
    Parse(String),
    /// Semantic validation error
    #[error("Formula validation error: {0}")]
    Validation(String),
}

/// Abstract syntax tree representing a parsed statistical formula
#[derive(Debug, Clone, PartialEq)]
pub struct ModelSpec {
    /// The response variable(s)
    pub response: Vec<String>,
    /// The predictor terms
    pub terms: Vec<Term>,
}

/// A term in a statistical formula
#[derive(Debug, Clone, PartialEq)]
pub enum Term {
    /// Intercept term
    Intercept,
    /// Variable name
    Variable(String),
    /// Interaction between terms
    Interaction(Vec<Term>),
    /// Function call (e.g., I(x^2), poly(x, 2))
    Function { name: String, args: Vec<String> },
}

impl ModelSpec {
    /// Create a simple formula with intercept
    pub fn intercept_only(response: &str) -> Self {
        Self {
            response: vec![response.to_string()],
            terms: vec![Term::Intercept],
        }
    }

    /// Add a variable term
    pub fn add_variable(&mut self, var: &str) {
        self.terms.push(Term::Variable(var.to_string()));
    }
}

/// Parse a formula string into a ModelSpec
pub fn parse_formula(_formula: &str) -> Result<ModelSpec, FormulaError> {
    // TODO: Implement pest-based parser in Sprint 2
    // For now, return a simple intercept-only model for testing
    Ok(ModelSpec::intercept_only("y"))
}

