→ **Suggested Fix:**
```rust
pub fn build(self) -> Array2<f64> {
    if self.columns.is_empty() {
        return Array2::zeros((self.n_rows, 0));
    }

    let n_cols = self.columns.len();
    // Flatten the column data.
    let data: Vec<f64> = self.columns.into_iter().flatten().collect();

    // Create the array from the flattened data. Note the 'f' for column-major order.
    Array2::from_shape_vec((self.n_rows, n_cols), data)
        .expect("Shape and data length mismatch, this should not happen")
}
